INSERT INTO intel_items (title, source, date, category, summary, keywords, scene_tags, score, is_verified) VALUES
-- 核心政策
('《无人驾驶航空器飞行管理暂行条例》正式生效', '国务院、中央军委令第761号', '2024-01-01', 'policy', '我国首部专门规范无人机飞行管理的行政法规。明确无人机五类分类标准（微/轻/小/中/大型）、实名登记制度、空域管理规定、操控员资质要求及法律责任。', ARRAY['暂行条例','无人机','实名登记','空域管理'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 98, TRUE),
('低空经济首次写入政府工作报告', '国务院', '2024-03-05', 'policy', '2024年政府工作报告明确提出"积极打造生物制造、商业航天、低空经济等新增长引擎"。低空经济从行业概念正式上升为国家级战略。', ARRAY['政府工作报告','低空经济','国家战略'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 97, TRUE),
('GB 46761-2025 实名登记和激活要求', '国家市场监督管理总局、民航局', '2026-05-01', 'policy', '强制性国家标准，落实民用无人驾驶航空器实名登记与激活，从技术上支撑"谁能飞"管理。运营前必须完成实名登记与激活流程。', ARRAY['GB 46761','强制标准','实名登记','激活'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 96, TRUE),
('GB 46750-2025 运行识别规范', '国家市场监督管理总局、民航局', '2026-05-01', 'policy', '强制性国家标准，要求运行识别信息报送，与广播式发送、网络式发送等能力相关。报送时间间隔、存储时长等定量指标以标准正文为准。', ARRAY['GB 46750','强制标准','运行识别','广播式'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 96, TRUE),
('新修订《民用航空法》2026年7月1日施行', '全国人大', '2025-12-27', 'policy', '第十四届全国人大常委会第十九次会议修订通过，无人驾驶航空器等内容与《暂行条例》等行政法规衔接，提供上位法依据。', ARRAY['民用航空法','修订','上位法','无人驾驶航空器'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 95, TRUE),
('低空经济正式跻身"新兴支柱产业"', '十五五规划纲要', '2026-03-01', 'policy', '十五五规划明确低空经济为"新兴支柱产业"之一，三年三次战略跃升——从2024年"新增长引擎"到2025年"新兴产业"再到2026年"新兴支柱产业"。', ARRAY['十五五','支柱产业','战略跃升'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 95, TRUE),
('低空经济标准体系建设指南（2025年版）', '国家市场监督管理总局等十部门', '2026-02-01', 'policy', '低空经济领域标准体系顶层设计的政策文件。将医疗物资低空运投等列为标准体系建设关注场景。投标"标准对标"应直接引用市场监管总局公开的 PDF 正文。', ARRAY['标准体系','十部门','指南','标准对标'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 94, TRUE),
('发改委低空司推进"扫码飞"审批改革', '国务院新闻办', '2026-04-17', 'policy', '国家发改委低空经济发展司推进无人机飞行审批数字化改革，目标是让合规飞行"无感"、违规飞行"无机可乘"。', ARRAY['发改委','低空司','扫码飞','审批改革'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 92, TRUE),

-- 技术与应用
('eVTOL 三大技术路线：多旋翼 vs 复合翼 vs 倾转旋翼', '行业分析', '2026-05-05', 'article', '多旋翼（约23%厂商采用）：结构简单、悬停稳定，但航程短、速度低，适合城市内短途。复合翼（约42%）：兼具悬停与高效巡航，技术成熟度较高，适航路径清晰。倾转旋翼（约35%）：巡航效率最高、速度快，但倾转机构复杂、适航难度大。', ARRAY['eVTOL','技术路线','多旋翼','复合翼','倾转旋翼'], ARRAY['高楼灭火','医疗应急'], 88, FALSE),
('《医疗机构临床用血管理办法》修订', '国家卫生健康委令第8号', '2019-01-01', 'policy', '第十五条规定医疗机构对血液预订、接收、入库、储存、出库及库存预警的管理须保证血液储存、运送符合国家有关标准。第十八条规定全血、红细胞储藏温度 2–6℃。', ARRAY['临床用血','管理办法','温度','红细胞'], ARRAY['医疗应急'], 90, TRUE),
('WS 400—2023《血液运输标准》', '国家卫生健康委', '2023-09-01', 'policy', '强制性卫生行业标准，适用于血站—医疗机构等环节血液运输技术要求。具体温度区段与监测频次以标准 PDF 为准。', ARRAY['WS 400','血液运输','卫生标准','强制性'], ARRAY['医疗应急'], 90, TRUE),
('无人机实名登记与运行识别规定（CCAR-92）', '民航局', '2024-01-01', 'policy', '无人机运行安全管理的第一份规章性文件。要求生产者确保无人机具备实名登记后方可激活使用的功能。"未激活不起飞"为自检底线。', ARRAY['CCAR-92','实名登记','激活','适航'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 91, TRUE),

-- 企业里程碑
('亿航智能获全球首张无人驾驶 eVTOL 型号合格证', '民航局 / 亿航智能', '2025-10-01', 'funding', '亿航智能 EH216-S 获得中国民航局颁发的全球首张无人驾驶载人 eVTOL 航空器型号合格证，标志着 eVTOL 行业从技术验证正式进入商业化运营阶段。', ARRAY['eVTOL','型号合格证','EH216-S','商业化'], ARRAY['高楼灭火','医疗应急'], 94, TRUE),
('沃飞长空 D 轮融资近 10 亿元，冲刺科创板', '四川证监局 / 36氪', '2026-04-15', 'funding', '沃飞长空完成股份制改造，注册资本增至 3.6 亿元，已向四川证监局提交 IPO 辅导备案。累计完成五轮融资，AE200 系列已获千余架订单。', ARRAY['IPO','融资','AE200','低空经济第一股'], ARRAY['高楼灭火','医疗应急'], 91, TRUE),
('边界智控完成亿元 B 轮融资', '36氪', '2026-04-20', 'funding', '边界智控完成亿元 B 轮融资，其自主研发的适航级三余度双通道飞控系统是国内首个专为 eVTOL 研发的飞控产品，填补了该领域的空白。', ARRAY['飞控系统','融资','适航','eVTOL'], ARRAY['高楼灭火','山林搜救'], 86, TRUE),
('小鹏汇天获近 2 亿美元融资，亚洲最大载人低空融资', '36氪', '2026-03-01', 'funding', '小鹏汇天宣布获得近 2 亿美元融资，成为亚洲载人低空领域迄今最大单笔融资。资金将用于"陆地航母"飞行汽车的研发与量产准备。', ARRAY['飞行汽车','融资','小鹏','陆地航母'], ARRAY['高楼灭火'], 85, TRUE),
('渤海地区鸿雁 HY100 完成大连-青岛 340 公里跨海低空航线', '大连发布', '2026-04-29', 'product', '鸿雁 HY100 大型无人机完成大连至青岛 340 公里跨海低空航线飞行，验证了长距离跨海物流运输的技术可行性。', ARRAY['无人机','跨海','航线','物流'], ARRAY['医疗应急'], 82, TRUE),

-- 国际对标
('欧盟 EASA 低空监管框架', 'EASA', '2024-01-01', 'article', 'EASA 建立了全球首个针对 eVTOL 运行的全面监管框架（SC-VTOL），将 eVTOL 运营按风险分为不同类别，制定差异化适航与运行标准。', ARRAY['EASA','监管','eVTOL','欧盟'], ARRAY['高楼灭火','医疗应急'], 85, FALSE),
('中美低空监管框架对比', '行业分析', '2026-05-05', 'article', '中国侧重"管得住、放得开"——先建标准再开空域；美国 FAA 侧重"基于性能的适航"——按运行风险分级管理。中国强制性国标体系完善度高于 FAA Advisory Circular。', ARRAY['中美对比','监管','FAA','适航'], ARRAY['高楼灭火','公安执法'], 83, FALSE),

-- 市场规模预测
('2035 年低空经济市场规模预测', '国务院发展研究中心/民航局', '2026-01-01', 'article', '国务院发展研究中心预测 2030 年达 1.5 万亿；民航局预测 2035 年突破 3.5 万亿；信通院预测 2035 年攀升至 5 万亿。全国无人机产值已达 2900 亿元。', ARRAY['市场规模','万亿','预测','无人机'], ARRAY['高楼灭火','山林搜救','公安执法','医疗应急'], 88, FALSE)
